<?php
if (($_GET['key'] ?? '') !== 'cv_fix_now') { http_response_code(403); die(); }
header('Content-Type: text/plain');

$scanner_path = __DIR__ . '/scanner.php';
$collection_path = __DIR__ . '/collection.php';

// Read current scanner.php from server
$scanner = file_get_contents($scanner_path);
if (!$scanner) { die('Cannot read scanner.php'); }

// The CSS that needs to be injected
$css = base64_decode('');

// Find and replace the empty style block OR inject after the first <style> tag
// Current server has: <style></style> (empty) or style block with wrong content
// We want: <style>$css</style>

// Strategy: find all style blocks and replace the one that's empty or wrong
$fixed = preg_replace_callback('/<style>(.*?)<\/style>/s', function($m) use ($css) {
    $content = trim($m[1]);
    // If it's the mobile wordmark one, leave it alone
    if (strpos($content, 'cv-mobile-wordmark') !== false) return $m[0];
    // If it's empty or doesn't have cat-zone CSS, replace it
    if (empty($content) || strpos($content, 'cat-zone') === false) {
        return '<style>' . $css . '</style>';
    }
    return $m[0];
}, $scanner, 1);

if (strpos($fixed, 'cat-grid') === false) {
    // Couldn't find/fix the style block - inject before </head>
    $fixed = str_replace('</head>', '<style>' . $css . '</style></head>', $scanner);
}

$bytes = file_put_contents($scanner_path, $fixed);
$styles_after = substr_count($fixed, '<style>');
$has_cat = strpos($fixed, 'cat-grid') !== false;
echo "scanner.php: $bytes bytes, style_blocks=$styles_after, cat-grid=" . ($has_cat?'YES':'NO') . "\n";

unlink(__FILE__);
echo 'patcher done';
